    "id": "unit-converter",
    "mode": "form_driven",
    "featured": true,
    "name": "Unit Converter",
    "tagline": "Convert length, weight, temperature, area, speed and more",
    "description": "Convert values between common measurement units: length (km, miles, meters, feet), weight (kg, lbs, oz), temperature (°C, °F, K), area (m², ft², acres), speed (km/h, mph, m/s), and volume (liters, gallons, fl oz).",
