    function _jsonSafe(s) {
      return String(s || '').replace(/"/g, '\\"');
    }

    function _safeIdOf(plugin) {
      var id = (plugin && plugin.id) || 'plugin';
      return String(id).replace(/[^a-z0-9]/gi, '_');
    }

